SELECT * FROM relic_archive
WHERE 1=1

    AND archive_code LIKE CONCAT('%', #{archiveCode}, '%')


    AND archive_type = #{archiveType}


    AND status = #{status}


    AND relic_id = #{relicId}

ORDER BY created_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM relic_archive
WHERE 1=1

    AND archive_code LIKE CONCAT('%', #{archiveCode}, '%')


    AND archive_type = #{archiveType}


    AND status = #{status}


    AND relic_id = #{relicId}
